SELECT id, functionary, name, type, description, duration, end_time, cover_path, created_at, submitted_by
FROM pending_activities
WHERE id = #{id}

SELECT COUNT(1)
FROM pending_activities

    AND type = #{type}
    AND functionary = #{functionary}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND submitted_by = #{submittedBy}

SELECT id, functionary, name, type, description, duration, end_time, cover_path, created_at, submitted_by
FROM pending_activities

    AND type = #{type}
    AND functionary = #{functionary}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND submitted_by = #{submittedBy}

ORDER BY created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

